#!/usr/bin/env bash
set -Eeuo pipefail
source "$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd -P)/lib/common.sh"
source "$(os_release_file)"; if [[ "${ID:-}" == ubuntu ]]; then report PASS "operating-system family observed: Ubuntu"; else report FAIL "unexpected operating-system family"; fi; report PASS "architecture observed: $(machine_arch)"; if python3.12 --version >/dev/null 2>&1; then report PASS "Python 3.12 available"; else report FAIL "Python 3.12 unavailable"; fi; [[ -x "$HOME/.local/share/mtaw/venv/bin/jupyter" ]] && report PASS "Jupyter environment available" || report WARN "Jupyter environment not observed"; command -v firefox >/dev/null 2>&1 && report PASS "Firefox available" || report WARN "Firefox not observed"; if command -v chromium >/dev/null 2>&1 || command -v chromium-browser >/dev/null 2>&1; then report PASS "Chromium available"; else report WARN "Chromium not observed"; fi; [[ -d "$HOME/MTAW-Workspace/notebooks" ]] && report PASS "workspace templates available" || report WARN "workspace templates not observed"; report 'NOT APPLICABLE' "report distinguishes repository checks from workstation validation"
